// src/generators/docs-generator.ts
function toRoutePath5(name) {
  const kebab = toKebabCase(name);
  if (kebab.endsWith("y")) return kebab.slice(0, -1) + "ies";
  if (kebab.endsWith("s") || kebab.endsWith("x") || kebab.endsWith("ch") || kebab.endsWith("sh")) {
    return kebab + "es";
  }
  return kebab + "s";
}
function mapFieldType(field) {
  if (field.kind === "enum") return field.type;
  if (field.kind === "object") return field.isList ? `${field.type}[]` : field.type;
  switch (field.type) {
    case "String":
      return "string";
    case "Int":
    case "Float":
    case "Decimal":
      return "number";
    case "Boolean":
      return "boolean";
    case "DateTime":
      return "Date";
    case "Json":
      return "Record<string, unknown>";
    case "BigInt":
      return "bigint";
    case "Bytes":
      return "Buffer";
    default:
      return "unknown";
  }
}
function describeField(field) {
  const parts = [];
  if (field.isId) parts.push("Primary key");
  if (field.isUnique) parts.push("Unique");
  if (!field.isRequired) parts.push("Nullable");
  if (field.hasDefaultValue) parts.push("Auto-generated");
  if (field.kind === "enum") parts.push(`Enum`);
  if (field.relationName) parts.push(`Relation`);
  return parts.join(", ") || "\u2014";
}
