function getExampleValue(field) {
  if (field.kind === "enum") return `"VALUE"`;
  switch (field.type) {
    case "String":
      return field.name.includes("email") ? '"user@example.com"' : field.name.includes("url") || field.name.includes("Url") ? '"https://example.com"' : field.name === "name" ? `"Example ${field.name}"` : `"string"`;
    case "Int":
      return "1";
    case "Float":
    case "Decimal":
      return "1.0";
    case "Boolean":
      return "true";
    case "DateTime":
      return '"2025-01-01T00:00:00Z"';
    case "Json":
      return "{}";
    default:
      return "null";
  }
}
function getExampleValueTS(field) {
  if (field.kind === "enum") return `'VALUE'`;
  switch (field.type) {
    case "String":
      return field.name.includes("email") ? "'user@example.com'" : field.name.includes("url") || field.name.includes("Url") ? "'https://example.com'" : field.name === "name" ? `'Example'` : `'...'`;
    case "Int":
      return "1";
    case "Float":
    case "Decimal":
      return "1.0";
    case "Boolean":
      return "true";
    case "DateTime":
      return "new Date()";
    case "Json":
      return "{}";
    default:
      return "null";
  }
}
function createFields(scalarFields) {
  return scalarFields.filter((f) => {
    if (f.isId && f.hasDefaultValue) return false;
    if (f.name === "createdAt" || f.name === "updatedAt") return false;
    return f.isRequired && !f.hasDefaultValue;
  });
}

